def count_log_levels(logs):
    levels = ["ERROR", "WARN", "INFO", "DEBUG"]
    counts = {}
    for line in logs:
        for level in levels:
            if level in line:
                counts[level] = counts.get(level, 0) + 1
                break
    return counts
